+
+function normalizeReportRow(row: LooseRecord): LooseRecord {
+  const normalized: LooseRecord = {};
+  for (const [key, value] of Object.entries(row)) {
+    normalized[key] = typeof value === "string" ? normalizeRetiredTerms(value) : value;
+  }
+  return normalized;
+}
